1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array when given empty array", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty array when a single live cell dies (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should return empty array when two adjacent live cells both die (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a 2x2 block stable (still life - survival with 3 neighbors)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(new Set(result.map(([x, y]) => `${x},${y}`))).toEqual(
19	      new Set(block.map(([x, y]) => `${x},${y}`))
20	    );
21	  });
22	  it("should kill center cell with 4 neighbors (overpopulation)", () => {
23	    // Center cell (1,1) has 4 live neighbors: corners + edges
24	    const cells: [number, number][] = [
25	      [0, 0], [1, 0], [2, 0],
26	      [0, 1], [1, 1],
27	      [0, 2], [2, 2],
28	    ];
29	    const result = nextGeneration(cells);
30	    const resultSet = new Set(result.map(([x, y]) => `${x},${y}`));
31	    expect(resultSet.has("1,1")).toBe(false);
32	  });
33	  it("should bring dead cell to life with exactly 3 neighbors (reproduction)", () => {
34	    // L-shape: dead cell (1,1) has exactly 3 neighbors
35	    const cells: [number, number][] = [[0, 0], [1, 0], [0, 1]];
36	    const result = nextGeneration(cells);
37	    const resultSet = new Set(result.map(([x, y]) => `${x},${y}`));
38	    expect(resultSet.has("1,1")).toBe(true);
39	  });
40	  it("should oscillate a vertical blinker into a horizontal blinker", () => {
41	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
42	    const result = nextGeneration(vertical);
43	    const resultKeys = new Set(result.map(([x, y]) => `${x},${y}`));
